import{isFile}from"../../util/fs.js";import{toEntry}from"../../util/input.js";const title="Yarn",enablers="This plugin is enabled when a `yarn.lock` file is found in the root folder.",isEnabled=async({cwd:n})=>isFile(n,"yarn.lock"),isRootOnly=!0,config=[".yarnrc.yml"],entry=["yarn.config.cjs"],resolveConfig=n=>{const t=entry.map(n=>toEntry(n));if(Array.isArray(n.plugins))for(const r of n.plugins)"string"==typeof r?t.push(toEntry(r)):"string"==typeof r.path&&t.push(toEntry(r.path));return n.yarnPath&&t.push(toEntry(n.yarnPath)),t},plugin={title:title,enablers:enablers,isEnabled:isEnabled,isRootOnly:true,config:config,entry:entry,resolveConfig:resolveConfig};export default plugin;